if (!function_exists('vs08v_flag_emoji')) {
    function vs08v_flag_emoji($code) {
        $code = trim($code);
        if (mb_strlen($code) > 2 || !ctype_alpha($code)) return $code;
        $code = strtoupper($code);
        $flag = '';
        foreach (str_split($code) as $c) $flag .= mb_chr(0x1F1E6 + (ord($c) - ord('A')), 'UTF-8');
        return $flag;
    }
}
