/* ── PRINT ── */
@media print{
    /* Masquer tout sauf l'essentiel */
    .sv-navbar, #sv-navbar-spacer,
    .sv-right-col,
    #sec-photos, .sv-carousel-wrap,
    .sv-hero-meta,
    #wpadminbar,
    footer, .site-footer, #colophon,
    .sv-action-print, .sv-action-pdf,
    #sv-lightbox
    { display:none!important }

    /* Reset page */
    * { -webkit-print-color-adjust:exact; print-color-adjust:exact }
    body { font-family: Georgia, serif; background:#fff!important; margin:0; padding:0 }

    /* Logo print en haut de page */
    .sv-print-logo{ display:block!important }
    a { color: inherit; text-decoration:none }

    /* Hero compact */
    .sv-hero { height:220px!important; min-height:0!important; page-break-after:avoid }
    .sv-hero-content { padding:0 30px 24px!important }
    .sv-hero h1 { font-size:28px!important }

    /* Page 1 colonne */
    .sv-page { background:#fff!important; padding:0!important }
    .sv-page-inner { grid-template-columns:1fr!important; padding:0 30px!important; gap:0!important }

    /* Cards épurées */
    .sv-left-col { gap:0!important }
    .sv-card, .sv-carousel-wrap {
        border-radius:0!important;
        box-shadow:none!important;
        border:none!important;
        border-bottom:1px solid #dde!important;
        padding:20px 0!important;
        page-break-inside:avoid
    }
    .sv-section-title { font-size:15px!important; margin-bottom:12px!important }

    /* Map pleine largeur */
    #sv-map, #sv-map iframe { height:220px!important }

    /* Pas de saut de page intempestif */
    .sv-card { page-break-inside:avoid }
}
/* ── RESPONSIVE ── */
