            <?php if(!empty($hotel['map_embed_url'])): ?>
            <div style="border-radius:12px;overflow:hidden;height:300px;border:1px solid #e5e7eb">
                <iframe width="100%" height="300" frameborder="0" style="border:0;display:block"
                    src="<?php echo esc_url($hotel['map_embed_url']); ?>&t=k&output=embed"
