<script>
// Alias : le plugin expose vs08v, ce template utilise VS08V (évite 500 / requête mal envoyée)
if (typeof window.VS08V === 'undefined' && typeof window.vs08v !== 'undefined') { window.VS08V = window.vs08v; }
// ── NAVBAR sticky — colle sous le header thème ─
(function(){
    var nav      = document.getElementById('sv-navbar');
    var rightCol = document.querySelector('.sv-right-col');

    // Calcule la hauteur des éléments fixes AU-DESSUS de la navbar
    // Méthode : getBoundingClientRect().bottom du header thème = position visuelle réelle
    // → gère automatiquement la admin bar WP (32px desktop / 46px mobile) sans calcul manuel
    function getHeaderH(){
        var themeHeader = document.getElementById('vs08-header');
        if(themeHeader){
            var rect = themeHeader.getBoundingClientRect();
            // .bottom = distance entre le haut du viewport et le bas du header
            // Fonctionne que l'admin bar soit présente ou non
            return Math.max(0, rect.bottom);
        }
        // ── Fallback si le header VS08 n'est pas trouvé ──
        var h = 0;
        var adminBar = document.getElementById('wpadminbar');
        if(adminBar) h += adminBar.offsetHeight;
        var selectors = ['#masthead','#site-header','.site-header','header.header-main',
                         '.header-sticky','.sticky-header','#header','.main-header'];
        for(var i = 0; i < selectors.length; i++){
            var el = document.querySelector(selectors[i]);
            if(el && el !== nav){
                var pos = window.getComputedStyle(el).position;
                if(pos === 'fixed' || pos === 'sticky') h += el.offsetHeight;
            }
        }
        return h;
    }

    function applyOffsets(){
        var hh   = getHeaderH();
        var navH = nav ? nav.offsetHeight : 52;
        // sticky top = hauteur des headers fixes au-dessus (recalculé en live)
        if(nav)      nav.style.top      = hh + 'px';
        // colonne droite sticky commence sous la navbar
        if(rightCol) rightCol.style.top = (hh + navH + 14) + 'px';
    }

    window.addEventListener('load',   applyOffsets);
    window.addEventListener('resize', applyOffsets);
    // Recalcule à chaque scroll car le header rétrécit quand la barre d'annonce disparaît
    window.addEventListener('scroll', applyOffsets);
    setTimeout(applyOffsets, 100);
    setTimeout(applyOffsets, 500);

    // Active state au scroll
    var btns = document.querySelectorAll('.sv-nav-btn');
    var ids  = ['sec-presentation','sec-hebergement','sec-location','sec-transfert','sec-golf','sec-programme','sec-compris','sec-map','sec-photos'];
    window.addEventListener('scroll', function(){
        var hh   = getHeaderH();
        var navH = nav ? nav.offsetHeight : 52;
        var y    = window.scrollY + hh + navH + 30;
        for(var i = ids.length - 1; i >= 0; i--){
            var el = document.getElementById(ids[i]); if(!el) continue;
            if(el.offsetTop <= y){
                btns.forEach(function(b){ b.classList.remove('active'); });
                btns.forEach(function(b){
                    if(b.getAttribute('onclick') && b.getAttribute('onclick').indexOf(ids[i]) > -1)
                        b.classList.add('active');
                });
                break;
            }
        }
    });
})();

function svScrollTo(id){
    var el = document.getElementById(id); if(!el) return;
    var nav = document.getElementById('sv-navbar');
    var offset = nav ? (parseInt(nav.style.top) || 0) + nav.offsetHeight + 20 : 80;
    window.scrollTo({top: el.getBoundingClientRect().top + window.scrollY - offset, behavior:'smooth'});
}

// ── CARROUSEL + LIGHTBOX ─────────────────────
(function(){
    var track=document.getElementById('sv-carousel-track'); if(!track) return;
    var dots=document.querySelectorAll('.sv-dot');
    var counter=document.getElementById('sv-counter');
    var imgs=[].slice.call(track.querySelectorAll('img'));
    var total=imgs.length, current=0, timer=null;
    function goTo(n){
        current=(n+total)%total;
        track.style.transform='translateX(-'+(current*100)+'%)';
        dots.forEach(function(d,i){d.classList.toggle('active',i===current);});
        if(counter)counter.textContent=(current+1)+' / '+total;
    }
    window.svGoto=function(n){stop();goTo(n);};
    function start(){timer=setInterval(function(){goTo(current+1);},2000);}
    function stop(){clearInterval(timer);timer=null;}
    var p=document.getElementById('sv-prev'),n=document.getElementById('sv-next');
    if(p)p.addEventListener('click',function(){stop();goTo(current-1);});
    if(n)n.addEventListener('click',function(){stop();goTo(current+1);});
    start();

    // LIGHTBOX
    var lb=document.getElementById('sv-lightbox');
    var lbImg=document.getElementById('sv-lb-img');
    var lbCounter=document.getElementById('sv-lb-counter');
    window.svLightboxOpen=function(){
        if(!lb||!imgs[current])return;
        stop(); // stopper l'auto-rotation
        lbImg.src=imgs[current].src;
        if(lbCounter)lbCounter.textContent=(current+1)+' / '+total;
        lb.classList.add('open');
        document.body.style.overflow='hidden';
    };
    window.svLightboxClose=function(){
        if(!lb)return;
        lb.classList.remove('open');
        document.body.style.overflow='';
        // Ne PAS relancer le timer — l'utilisateur a choisi de regarder
    };
    window.svLightboxNav=function(dir){
        var n=(current+dir+total)%total;
        goTo(n);
        if(lbImg&&imgs[n])lbImg.src=imgs[n].src;
        if(lbCounter)lbCounter.textContent=(n+1)+' / '+total;
    };
    // Fermer avec Echap
    document.addEventListener('keydown',function(e){
        if(e.key==='Escape')window.svLightboxClose();
        if(e.key==='ArrowLeft'&&lb&&lb.classList.contains('open'))window.svLightboxNav(-1);
        if(e.key==='ArrowRight'&&lb&&lb.classList.contains('open'))window.svLightboxNav(1);
    });
})();


// ── CALCULATEUR ───────────────────────────────
var svPrixVol=0, svPrixVolRef=0, svFlightsData=[], svTimer=null, svAirlineIata='';

// ── Barre sticky bouton réserver ──
(function(){
    var stickyBar = document.getElementById('sv-sticky-bar');
    var stickyBtn = document.getElementById('sv-sticky-btn');
    var origBtn   = document.getElementById('sv-btn-reserver');
    if(!stickyBar || !origBtn) return;

    // Observer : affiche la barre quand le bouton original sort du viewport
    var observer = new IntersectionObserver(function(entries){
        entries.forEach(function(e){
            if(!origBtn.disabled){
                stickyBar.classList.toggle('visible', !e.isIntersecting);
            } else {
                stickyBar.classList.remove('visible');
            }
        });
    }, { threshold: 0, rootMargin: '0px' });

    // On observe après que le bouton soit rendu visible
    var btnObserver = new MutationObserver(function(){
        if(!origBtn.disabled){
            observer.observe(origBtn);
        } else {
            observer.unobserve(origBtn);
            stickyBar.classList.remove('visible');
        }
        if(stickyBtn) stickyBtn.disabled = origBtn.disabled;
    });
    btnObserver.observe(origBtn, { attributes: true, attributeFilter: ['disabled'] });
})();

// Met à jour le prix dans la barre sticky
function svUpdateStickyBar(priceText){
