    if(el) el.textContent = priceText || '—';
}

// Retourne true si la date (YYYY-MM-DD) est dans une période fermée à la vente (tous aéroports)
function svDateInClosedPeriod(dateStr) {
    if (!dateStr || !VS08V_VOYAGE.periodes_fermees_vente || !VS08V_VOYAGE.periodes_fermees_vente.length) return false;
    var t = new Date(dateStr + 'T12:00:00').getTime();
    for (var i = 0; i < VS08V_VOYAGE.periodes_fermees_vente.length; i++) {
        var deb = VS08V_VOYAGE.periodes_fermees_vente[i].date_debut, fin = VS08V_VOYAGE.periodes_fermees_vente[i].date_fin;
        if (!deb && !fin) continue;
        var tDeb = deb ? new Date(deb + 'T00:00:00').getTime() : 0;
        var tFin = fin ? new Date(fin + 'T23:59:59').getTime() : 9e12;
        if (t >= tDeb && t <= tFin) return true;
    }
    return false;
}

// Retourne true si la date (YYYY-MM-DD) est autorisée pour l'aéroport (périodes + jours par période)
function svDateAllowedForAeroport(dateStr, code) {
    if (!code || !VS08V_VOYAGE.aeroports || !dateStr) return true;
    var a = VS08V_VOYAGE.aeroports.find(function(x){ return (x.code||'').toUpperCase() === (code||'').toUpperCase(); });
    if (!a) return true;
    var periodes = a.periodes_vol || [];
    var joursDefaut = a.jours_direct || [1,2,3,4,5,6,7];
    var d = new Date(dateStr + 'T12:00:00');
    var jsDay = d.getDay();
    var phpDay = jsDay === 0 ? 7 : jsDay;
    if (periodes.length === 0) return joursDefaut.length === 0 || joursDefaut.indexOf(phpDay) !== -1;
    var t = d.getTime();
    for (var i = 0; i < periodes.length; i++) {
        var deb = periodes[i].date_debut, fin = periodes[i].date_fin;
        if (!deb && !fin) continue;
        var tDeb = deb ? new Date(deb + 'T00:00:00').getTime() : 0;
        var tFin = fin ? new Date(fin + 'T23:59:59').getTime() : 9e12;
        if (t >= tDeb && t <= tFin) {
            var joursPeriode = (periodes[i].jours_direct && periodes[i].jours_direct.length) ? periodes[i].jours_direct : joursDefaut;
            return joursPeriode.indexOf(phpDay) !== -1;
        }
    }
    return false;
}

// Liste des dates autorisées pour un aéroport (YYYY-MM-DD) sur 2 ans à partir d'aujourd'hui
// Exclut les dates situées dans une période fermée à la vente (tous aéroports)
function svGetAllowedDatesForAeroport(code) {
    if (!code || !VS08V_VOYAGE.aeroports) return null;
    var a = VS08V_VOYAGE.aeroports.find(function(x){ return (x.code||'').toUpperCase() === (code||'').toUpperCase(); });
    if (!a) return null;
    var out = [], today = new Date();
    for (var y = 0; y <= 2; y++) {
        for (var m = 0; m < 12; m++) {
            var last = new Date(today.getFullYear() + y, m + 1, 0).getDate();
            for (var day = 1; day <= last; day++) {
                var d = new Date(today.getFullYear() + y, m, day);
                if (d < today) continue;
                var yyyy = d.getFullYear(), mm = String(d.getMonth() + 1).padStart(2,'0'), dd = String(d.getDate()).padStart(2,'0');
                var dtStr = yyyy + '-' + mm + '-' + dd;
                if (svDateAllowedForAeroport(dtStr, code) && !svDateInClosedPeriod(dtStr)) out.push(dtStr);
            }
        }
    }
    return out;
}

function svOnAeroportChange(){
    var sel = document.getElementById('sv-aeroport');
    var dateBlock = document.getElementById('sv-field-date-block');
    var hint = document.getElementById('sv-date-hint');
    var feedback = document.getElementById('sv-date-feedback');
    if (!sel || !dateBlock) return;
    var code = (sel.value || '').trim();

    if (!code) {
        dateBlock.style.display = 'none';
        if (hint) hint.style.display = 'block';
        var step2 = document.getElementById('sv-step2');
        if (step2) step2.style.display = 'none';
        return;
    }

    dateBlock.style.display = 'block';
    if (hint) hint.style.display = 'none';
    if (feedback) feedback.style.display = 'none';

    var dateSelect = dateBlock.querySelector('select#sv-date-depart');
    var dateWrap = document.getElementById('sv-date-wrap');
    if (dateSelect) {
        dateSelect.style.display = 'block';
        [].forEach.call(dateSelect.options, function(opt) {
            if (opt.value === '') { opt.disabled = false; return; }
            opt.disabled = !svDateAllowedForAeroport(opt.value, code);
            if (opt.selected && opt.disabled) dateSelect.value = '';
        });
    } else if (dateWrap) {
        dateWrap.style.display = 'block';
        var allowed = svGetAllowedDatesForAeroport(code);
        var iataDest = (VS08V_VOYAGE.iata_dest || '').trim();
        var dureeNuits = VS08V_VOYAGE.duree || 7;
        // Trouver le premier mois avec un vol disponible
        var firstAvailMonth = null, firstAvailYear = null;
        if (allowed.length > 0) {
            allowed.sort();
            var parts = allowed[0].split('-');
            firstAvailYear = parseInt(parts[0]);
            firstAvailMonth = parseInt(parts[1]) - 1;
        }

        if (!window.svCalDate && typeof VS08Calendar !== 'undefined') {
            dateWrap.innerHTML = '';
            window.svCalDate = new VS08Calendar({
                el: '#sv-date-wrap', mode: 'date', inline: true, input: '#sv-date-depart',
                title: '📅 Date d\'aller · ' + code + ' → ' + iataDest,
                subtitle: 'Retour auto après ' + dureeNuits + ' nuits. Cliquez sur un jour avec vol direct.',
                yearRange: [new Date().getFullYear(), new Date().getFullYear() + 2], minDate: new Date(Date.now() + 7 * 86400000), // J-7 fermeture ventes
                available: allowed,
                onSelect: function(dt) {
                    if (dt) {
                        var ds = dt.getFullYear() + '-' + String(dt.getMonth()+1).padStart(2,'0') + '-' + String(dt.getDate()).padStart(2,'0');
                        document.getElementById('sv-date-depart').value = ds;
                        document.getElementById('sv-date-depart').dispatchEvent(new Event('change', { bubbles: true }));
                    }
                }
            });
            if (firstAvailMonth !== null) {
                window.svCalDate.viewMonth = firstAvailMonth;
                window.svCalDate.viewYear = firstAvailYear;
                window.svCalDate.render();
            }
        } else if (window.svCalDate) {
            var cal = window.svCalDate;
            var dateVal = document.getElementById('sv-date-depart') ? document.getElementById('sv-date-depart').value : '';
            if (dateVal && (!svDateAllowedForAeroport(dateVal, code) || svDateInClosedPeriod(dateVal))) {
                var inp = document.getElementById('sv-date-depart');
                if (inp) inp.value = '';
                cal.selected = null;
                cal.selectedEnd = null;
            }
            if (typeof cal.setAvailable === 'function') {
                cal.setAvailable(allowed);
            } else {
                cal.opts.available = allowed;
            }
            if (cal.opts) {
                cal.opts.title = '📅 Date d\'aller · ' + code + ' → ' + iataDest;
                cal.opts.subtitle = 'Retour auto après ' + dureeNuits + ' nuits. Cliquez sur un jour avec vol direct.';
            }
            if (firstAvailMonth !== null) {
                cal.viewMonth = firstAvailMonth;
                cal.viewYear = firstAvailYear;
            }
            var wrap = cal.wrap;
            if (wrap) {
                var titleEl = wrap.querySelector('.vs-cal-header-title');
                var subEl = wrap.querySelector('.vs-cal-header-sub');
                if (titleEl) titleEl.textContent = cal.opts.title || '';
                if (subEl) subEl.textContent = cal.opts.subtitle || '';
            }
            cal.render();
        }
    }
    var dateVal = document.getElementById('sv-date-depart') ? document.getElementById('sv-date-depart').value : '';
    if (dateVal && (!svDateAllowedForAeroport(dateVal, code) || svDateInClosedPeriod(dateVal))) {
        var inp = document.getElementById('sv-date-depart');
        if (inp) inp.value = '';
        if (window.svCalDate) {
            window.svCalDate.selected = null;
            window.svCalDate.selectedEnd = null;
            window.svCalDate.render();
        }
    }
    svOnDateChange();
}

function svOnDateChange(){
    var dateEl = document.getElementById('sv-date-depart');
    var step2 = document.getElementById('sv-step2');
    var feedback = document.getElementById('sv-date-feedback');
    var date = dateEl ? dateEl.value : '';

    if (date) {
        var aeroSel = document.getElementById('sv-aeroport');
        var code = aeroSel ? aeroSel.value : '';
        if (code && (!svDateAllowedForAeroport(date, code) || svDateInClosedPeriod(date))) {
            dateEl.value = '';
            if (feedback) { feedback.textContent = svDateInClosedPeriod(date) ? 'Cette date est en période fermée à la vente.' : 'Pas de vol direct ce jour-là depuis cet aéroport.'; feedback.style.display = 'block'; }
            if (step2) step2.style.display = 'none';
            return;
        }
        if (feedback) feedback.style.display = 'none';
        step2.style.display = 'block';
        svBuildRooms();
        if (code) { svFetchVol(); } else { svUpdate(); }
    } else {
        if (step2) step2.style.display = 'none';
    }
}


function svBuildRooms(){
    var nb=parseInt(document.getElementById('sv-nb-chambres').value)||1;
    var list=document.getElementById('sv-rooms-list');
    list.innerHTML='';
    for(var r=1;r<=nb;r++){
        var box=document.createElement('div');
        box.className='sv-room-box';
        box.setAttribute('data-room',r);
        box.innerHTML='<p class="sv-room-box-title">🛏️ Chambre '+r+'</p>'+
            '<div class="sv-room-grid">'+
                '<div class="sv-room-field"><label>Type</label>'+
                    '<select class="sv-room-type" onchange="svEnforceRoomRules(this);svUpdate()">'+
                        '<option value="double">Double</option>'+
                        '<option value="simple">Individuelle</option>'+
                        '<option value="triple">Triple</option>'+
                    '</select></div>'+
                '<div class="sv-room-field"><label>Golfeurs</label>'+
                    '<select class="sv-room-golf" onchange="svUpdate()">'+
                        [0,1,2].map(function(i){return '<option value="'+i+'"'+(i===2?' selected':'')+'>'+i+'</option>';}).join('')+
                    '</select></div>'+
                '<div class="sv-room-field"><label>Accomp.</label>'+
                    '<select class="sv-room-nongolf" onchange="svUpdate()">'+
                        [0,1,2].map(function(i){return '<option value="'+i+'"'+(i===0?' selected':'')+'>'+i+'</option>';}).join('')+
                    '</select></div>'+
            '</div>';
        list.appendChild(box);
        svEnforceRoomRules(box.querySelector('.sv-room-type'));
    }
    svUpdate();
}

// Règles : simple=1 adulte, double=2, triple=3
function svEnforceRoomRules(typeEl){
    var box=typeEl.closest('.sv-room-box');
    var golfSel=box.querySelector('.sv-room-golf');
    var nonSel=box.querySelector('.sv-room-nongolf');
    var type=typeEl.value;
    function buildOpts(sel,min,max,def){
        var cur=parseInt(sel.value)||0;
        sel.innerHTML='';
        for(var i=min;i<=max;i++){var o=document.createElement('option');o.value=i;o.textContent=i;if(i===def)o.selected=true;sel.appendChild(o);}
        if(cur>=min&&cur<=max)sel.value=cur;
    }
    if(type==='simple'){
        // 1 seul adulte total
        buildOpts(golfSel,0,1,1);
        buildOpts(nonSel,0,0,0);
        nonSel.disabled=true;
        // forcer total = 1
        if(parseInt(golfSel.value)+parseInt(nonSel.value)!==1)golfSel.value=1;
        golfSel.onchange=function(){
            var g=parseInt(this.value);
            nonSel.value=1-g>=0?1-g:0;
            svUpdate();
        };
    } else if(type==='double'){
        buildOpts(golfSel,0,2,2);
        buildOpts(nonSel,0,2,0);
        nonSel.disabled=false;
        golfSel.onchange=function(){
            var g=parseInt(this.value);
            var nn=2-g; if(nn<0)nn=0; if(nn>2)nn=2;
            nonSel.value=nn;
            svUpdate();
        };
        nonSel.onchange=function(){
            var nn=parseInt(this.value);
            var g=2-nn; if(g<0)g=0; if(g>2)g=2;
            golfSel.value=g;
            svUpdate();
        };
        golfSel.value=2; nonSel.value=0;
    } else if(type==='triple'){
        buildOpts(golfSel,0,3,3);
        buildOpts(nonSel,0,3,0);
        nonSel.disabled=false;
        golfSel.onchange=function(){
            var g=parseInt(this.value);
            var nn=3-g; if(nn<0)nn=0; if(nn>3)nn=3;
            nonSel.value=nn;
            svUpdate();
        };
        nonSel.onchange=function(){
            var nn=parseInt(this.value);
            var g=3-nn; if(g<0)g=0; if(g>3)g=3;
            golfSel.value=g;
            svUpdate();
        };
        golfSel.value=3; nonSel.value=0;
    }
}

// Toggle option — clic sur la ligne entière OU directement sur la checkbox
function svToggleOpt(row){
    var cb = row.querySelector('.sv-opt-cb');
    // Ne pas re-toggler si c'est déjà géré par la checkbox native
    cb.checked = !cb.checked;
    svApplyOptState(row, cb.checked);
}
function svApplyOptState(row, checked){
    row.classList.toggle('active', checked);
    var qtyEl = row.querySelector('.sv-opt-qty');
    if(qtyEl){
        qtyEl.style.display = checked ? 'flex' : 'none';
        qtyEl.classList.toggle('show', checked);
    }
    svUpdate();
}
// Empêcher le double-toggle quand on clique directement sur la checkbox
document.addEventListener('DOMContentLoaded', function(){
    document.querySelectorAll('.sv-opt-cb').forEach(function(cb){
        cb.addEventListener('change', function(e){
            e.stopPropagation();
            svApplyOptState(this.closest('.sv-option-row'), this.checked);
        });
    });
});

// Scroll isolé sur la calc-card : souris sur la card = molette scroll uniquement la card (pas la page)
document.addEventListener('DOMContentLoaded', function(){
    var card = document.querySelector('.sv-calc-card');
    if (!card) return;
    card.addEventListener('wheel', function(e) {
        var st = card.scrollTop, sh = card.scrollHeight, ch = card.clientHeight, maxScroll = sh - ch;
        if (maxScroll <= 0) return;
        var delta = e.deltaY, atTop = st <= 0, atBottom = st >= maxScroll - 1;
        if ((delta > 0 && !atBottom) || (delta < 0 && !atTop)) {
            e.preventDefault();
            card.scrollTop = Math.max(0, Math.min(maxScroll, st + delta));
        }
    }, { passive: false });
});

function svQty(id, delta){
    var valEl=document.getElementById('qval-'+id); if(!valEl) return;
    var v=parseInt(valEl.textContent)||1;
    v=Math.max(1, v+delta);
    valEl.textContent=v;
    svUpdate();
}

// Échapper HTML
function svEsc(s){ var d=document.createElement('div'); d.textContent=s||''; return d.innerHTML; }

function svSetCalendarConfirmEnabled(enabled) {
    var ob = document.getElementById('sv-btn-reserver');
    var sb = document.getElementById('sv-sticky-btn');
    if (ob) ob.disabled = !enabled;
    if (sb) sb.disabled = !enabled;
}

// ============================================================
// FETCH VOL — Badge statut uniquement (les vols s'affichent page suivante)
// ============================================================
function svFetchVol(){
    var aero = document.getElementById('sv-aeroport') ? document.getElementById('sv-aeroport').value : '';
    var date = document.getElementById('sv-date-depart') ? document.getElementById('sv-date-depart').value : '';
    var st   = document.getElementById('sv-vol-st');

    svVolReady = false;
    svPrixVol = 0;
    document.getElementById('sv-price-box').style.display='none';
    svSetCalendarConfirmEnabled(false);

    if(!aero || !date){
        document.getElementById('sv-price-loading').style.display='block';
        document.getElementById('sv-price-loading').textContent='✈️ Sélectionnez un aéroport pour voir le prix';
        return;
    }

    // Calculer la date de retour = date départ + durée (nuits)
    var duree = VS08V_VOYAGE.duree || 7;
    var dtDep = new Date(date);
    dtDep.setDate(dtDep.getDate() + duree);
    var dateRetour = dtDep.getFullYear() + '-' + String(dtDep.getMonth()+1).padStart(2,'0') + '-' + String(dtDep.getDate()).padStart(2,'0');

    // Compter les passagers depuis les rooms
    var totalPax = 0;
    document.querySelectorAll('.sv-room-box').forEach(function(box){
        totalPax += (parseInt(box.querySelector('.sv-room-golf').value)||0);
        totalPax += (parseInt(box.querySelector('.sv-room-nongolf').value)||0);
    });
    if(totalPax < 1) totalPax = 1;

    // Badge orange — recherche en cours
    if(st){ st.className='sv-vol-st loading'; st.textContent='⏳ Recherche vols A/R directs (même compagnie)...'; }

    var restFlight = (window.VS08V && window.VS08V.rest_flight) ? window.VS08V.rest_flight : (window.vs08v && window.vs08v.rest_flight) ? window.vs08v.rest_flight : '';
    var ajaxUrl = (window.VS08V && window.VS08V.ajax_url) ? window.VS08V.ajax_url : (window.vs08v && window.vs08v.ajax_url) ? window.vs08v.ajax_url : '';
    var payload = { voyage_id: VS08V_VOYAGE.id, date: date, date_retour: dateRetour, aeroport: aero, passengers: totalPax };

    function onFlightResult(res) {
        if (!res || !res.success) {
            svPrixVol = 0; svVolReady = false;
            if (st) { st.className = 'sv-vol-st error'; st.textContent = '❌ Aucun vol direct trouvé pour cette date / cet aéroport.'; }
            document.getElementById('sv-price-box').style.display='none';
            document.getElementById('sv-price-loading').style.display='block';
            document.getElementById('sv-price-loading').textContent='Aucun vol direct disponible — choisissez une autre date ou un autre aéroport.';
            svSetCalendarConfirmEnabled(false);
            return;
        }
        svPrixVolRef  = res.data.ref_price_per_pax || res.data.prix || 0;
        svPrixVol     = svPrixVolRef;
        svFlightsData = res.data.flights || [];
        svAirlineIata = (svFlightsData.length > 0 && svFlightsData[0].airline_iata) ? svFlightsData[0].airline_iata : '';
        var nbVols = svFlightsData.length;
        if (nbVols === 0) {
            svVolReady = false;
            if (st) { st.className = 'sv-vol-st error'; st.textContent = '❌ Aucun vol direct trouvé pour cette date / cet aéroport.'; }
            document.getElementById('sv-price-box').style.display='none';
            document.getElementById('sv-price-loading').style.display='block';
            document.getElementById('sv-price-loading').textContent='Aucun vol direct disponible — choisissez une autre date ou un autre aéroport.';
            svSetCalendarConfirmEnabled(false);
            return;
        }
        svVolReady = true;
        var txt = '✅ ' + nbVols + ' vol' + (nbVols>1?'s':'') + ' A/R direct' + (nbVols>1?'s':'');
        if (st) { st.className = 'sv-vol-st loaded'; st.textContent = txt; }
        svSetCalendarConfirmEnabled(true);
        svUpdate();
    }
    function onFlightFail() {
        svPrixVol = 0; svVolReady = false;
        if (st) { st.className = 'sv-vol-st error'; st.textContent = '❌ Aucun vol direct trouvé pour cette date / cet aéroport.'; }
        document.getElementById('sv-price-box').style.display='none';
        document.getElementById('sv-price-loading').style.display='block';
        document.getElementById('sv-price-loading').textContent='Aucun vol direct disponible — choisissez une autre date ou un autre aéroport.';
        svSetCalendarConfirmEnabled(false);
    }

    if (restFlight) {
        jQuery.post(restFlight, payload).done(onFlightResult).fail(function() {
            if (ajaxUrl) {
                payload.action = 'vs08v_get_flight';
                payload.nonce = (window.VS08V && window.VS08V.nonce) ? window.VS08V.nonce : (window.vs08v && window.vs08v.nonce) ? window.vs08v.nonce : '';
                jQuery.post(ajaxUrl, payload).done(onFlightResult).fail(onFlightFail);
            } else { onFlightFail(); }
        });
    } else if (ajaxUrl) {
        payload.action = 'vs08v_get_flight';
        payload.nonce = (window.VS08V && window.VS08V.nonce) ? window.VS08V.nonce : (window.vs08v && window.vs08v.nonce) ? window.vs08v.nonce : '';
        jQuery.post(ajaxUrl, payload).done(onFlightResult).fail(onFlightFail);
    } else {
        onFlightFail();
    }
}

function svUpdate(){clearTimeout(svTimer);svTimer=setTimeout(svDoCalc,500);}

var svVolReady=false;

function svDoCalc(){
    var date=document.getElementById('sv-date-depart').value; if(!date) return;
    var aero=document.getElementById('sv-aeroport')?document.getElementById('sv-aeroport').value:'';
    var rooms=[],totalGolf=0,totalNonGolf=0;
    document.querySelectorAll('.sv-room-box').forEach(function(box){
        var ng=parseInt(box.querySelector('.sv-room-golf').value)||0;
        var nn=parseInt(box.querySelector('.sv-room-nongolf').value)||0;
        var tc=box.querySelector('.sv-room-type').value;
        totalGolf+=ng; totalNonGolf+=nn; rooms.push({ng:ng,nn:nn,tc:tc});
    });
    if(!rooms.length||totalGolf+totalNonGolf===0) return;

    // Ne pas afficher de prix ni permettre d'avancer tant que le vol n'a pas été récupéré (ou 0 vol direct)
    if(!aero || !svVolReady){
        document.getElementById('sv-price-box').style.display='none';
        document.getElementById('sv-price-loading').style.display='block';
        document.getElementById('sv-price-loading').textContent='✈️ Sélectionnez un aéroport pour voir le prix';
        svSetCalendarConfirmEnabled(false);
        return;
    }

    document.getElementById('sv-price-loading').style.display='none';
    document.getElementById('sv-price-box').style.opacity='0.35';

    var restCalc = (window.VS08V && window.VS08V.rest_calculate) ? window.VS08V.rest_calculate : (window.vs08v && window.vs08v.rest_calculate) ? window.vs08v.rest_calculate : '';
    var calcUrl = (window.VS08V && window.VS08V.ajax_url) ? window.VS08V.ajax_url : (window.vs08v && window.vs08v.ajax_url) ? window.vs08v.ajax_url : '';
    var calcPayload = {
        voyage_id: VS08V_VOYAGE.id, date_depart: date, aeroport: aero,
        nb_golfeurs: totalGolf, nb_nongolfeurs: totalNonGolf,
        type_chambre: rooms[0].tc, nb_chambres: rooms.length,
        prix_vol: svPrixVol, airline_iata: svAirlineIata, rooms: JSON.stringify(rooms), options: '[]'
    };
    function doCalcPost(url, data, done) {
        jQuery.post(url, data).done(done).fail(function() {
            if (calcUrl && url !== calcUrl) {
                data.action = 'vs08v_calculate';
                data.nonce = (window.VS08V && window.VS08V.nonce) ? window.VS08V.nonce : (window.vs08v && window.vs08v.nonce) ? window.vs08v.nonce : '';
                jQuery.post(calcUrl, data).done(done);
            }
        });
    }
    var calcDone = function(res){
        document.getElementById('sv-price-loading').style.display='none';
        if(!res.success) return;
        var d=res.data;
        var grand=Math.ceil(parseFloat(d.total||0));
        var nb=totalGolf+totalNonGolf;
        var pp=nb>0?Math.ceil(grand/nb):grand;

        // ── RÈGLE : l'acompte ne peut JAMAIS être inférieur au prix des vols ──
        var acompteMode = VS08V_VOYAGE.acompte_mode || 'pct';
        var acomptePct = parseFloat(d.acompte_pct_final || d.acompte_pct || 30);
        var acompteLabel, acompteVal;

        if(acompteMode === 'eur' && VS08V_VOYAGE.acompte_eur > 0){
            acompteVal = Math.ceil(VS08V_VOYAGE.acompte_eur);
            var coutVolTotal = svPrixVol * nb;
            if(coutVolTotal > acompteVal) acompteVal = Math.ceil(coutVolTotal);
            acompteLabel = 'Acompte à la réservation : '+svFmt(acompteVal);
        } else {
            acompteVal = grand * acomptePct / 100;
            var coutVolTotal = svPrixVol * nb;
            if(coutVolTotal > 0 && acompteVal < coutVolTotal && grand > 0){
                var pctReel = (coutVolTotal / grand) * 100;
                acomptePct = Math.ceil(pctReel / 5) * 5;
                acompteVal = grand * acomptePct / 100;
            }
            acompteVal = Math.ceil(acompteVal);
            acompteLabel = 'Acompte '+acomptePct+'% = '+svFmt(acompteVal);
        }

        document.getElementById('sv-price-val').textContent=svFmt(grand);
        document.getElementById('sv-price-pp').textContent=svFmt(pp);
        document.getElementById('sv-price-acompte').textContent=acompteLabel;
        document.getElementById('sv-price-box').style.opacity='1';
        document.getElementById('sv-price-box').style.display='block';
        svUpdateStickyBar(svFmt(grand));
        document.getElementById('sv-btn-reserver').disabled=false;
        window.svParams={date_depart:date,aeroport:aero,nb_golfeurs:totalGolf,nb_nongolfeurs:totalNonGolf,type_chambre:rooms[0].tc,nb_chambres:rooms.length,prix_vol:svPrixVol,airline_iata:svAirlineIata,rooms:rooms,options:[]};
    };
    if (restCalc) {
        doCalcPost(restCalc, calcPayload, calcDone);
    } else if (calcUrl) {
        var ajaxPayload = Object.assign({}, calcPayload);
        ajaxPayload.action = 'vs08v_calculate';
        ajaxPayload.nonce = (window.VS08V && window.VS08V.nonce) ? window.VS08V.nonce : (window.vs08v && window.vs08v.nonce) ? window.vs08v.nonce : '';
        doCalcPost(calcUrl, ajaxPayload, calcDone);
    }
}

function svFmt(n){return Math.ceil(parseFloat(n)||0).toLocaleString('fr-FR',{minimumFractionDigits:0,maximumFractionDigits:0})+' €';}
function svGoReserver(){
    if(!window.svParams)return;
    var p=window.svParams;
    window.location.href=VS08V_VOYAGE.booking_url+'?date='+encodeURIComponent(p.date_depart)+'&aeroport='+encodeURIComponent(p.aeroport||'')+'&ngolf='+p.nb_golfeurs+'&nngolf='+p.nb_nongolfeurs+'&chambre='+p.type_chambre+'&nchamb='+p.nb_chambres+'&vol='+p.prix_vol+'&airline='+encodeURIComponent(p.airline_iata||'');
}

document.addEventListener('DOMContentLoaded',function(){svBuildRooms();});
</script>

